/* cotTruyen q11 (56 chương) — engine-API cotTruyen */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q11"]=window.__LIBQ["tien-nghich"]["q11"]||{};window.__LIBQ["tien-nghich"]["q11"]["cotTruyen"]=[{"chuong":1214,"tieuDe":"Thức Tỉnh!","tomTat":"Trải qua mười năm, Lý Thiến Mai liên tục hy sinh máu tươi, tinh huyết tâm thần, đạo huyết nguyên thần và cả ngọc bội mệnh hồn để nuôi dưỡng tượng đá Vương Lâm, thân thể nàng suy kiệt hoàn toàn. Khi mọi thứ vẫn không đủ, nàng rời đại lục hoang dã quay về Yêu Tông đổi hồn huyết bằng cách chấp nhận điều kiện tàn khốc: một mình xông vào khe sâu nhất chiến trường dò xét thông đạo giới ngoại, nơi chắc chắn phải chết. Sư tỷ của nàng, một bà lão bạch y tu vi Toái Niết đại viên mãn, mang hồn huyết tới sơn cốc dung nhập vào tượng đá, khiến Vương Lâm lần đầu mở mắt sau mười năm hôn mê. Thức tỉnh, hắn phát hiện mình đã tiến vào cảnh giới kỳ dị gọi là Đạo cảnh, có thể nhìn thấu nguyên thần và khống chế thần thông của người khác, khiến bà lão kinh hãi khi mọi bí mật trong người bà đều bị lộ. Bà lão kể lại toàn bộ sự hy sinh của Lý Thiến Mai suốt mười năm: từ bỏ vị trí đại đệ tử Yêu Tông, bị Phá Thiên Tông khai trừ, bị sư tôn giam cầm rồi lấy cái chết ép được tự do, và cuối cùng đem tính mạng đổi hồn huyết. Vương Lâm nghe xong run rẩy, lớp da đá trên người sụp đổ kéo theo cả đại lục hoang dã vỡ thành bốn năm mảnh vì tượng đá đã hòa làm một với đại lục. Tu vi kinh thiên động địa tuôn ra, hắn bắt lấy bà lão bắt dẫn đường, quyết tâm lao tới chiến trường Yêu Tông cứu Lý Thiến Mai."},{"chuong":1215,"tieuDe":"Ngàn Vạn Người Không Ngăn Nổi!","tomTat":"Sau khi nghe bà lão bạch y kể hết mọi chuyện về Lý Thiến Mai, Vương Lâm nói bốn chữ 'Ta đi cứu nàng!' rồi bỏ qua cả nhu cầu bế quan tăng hiểu biết Đạo cảnh lẫn nguy cơ Thác Sâm phát hiện ở giới ngoại, lao đi như lưu tinh kéo theo bà lão. Hắn nhớ lại lời ly biệt của Lý Thiến Mai tại Vô Cực Tông, đau đớn vì nợ nàng mười năm. Bà lão vạch lộ trình truyền tống nhiều chặng: Hải Hồn Tông → tinh vực cấp sáu → Tiên Âm Môn → Vô Cực Tông → tinh vực cấp chín → Yêu Tông. Vương Lâm phóng xuyên tinh vực cấp hai để lại khe nứt xé đôi cả tinh vực, vượt tinh vực cấp ba tiến vào tinh vực cấp bốn. Tại đại lục Hải Hồn Tông, hắn phá vỡ đại trận phòng hộ, uy hiếp tông chủ Khuy Niết đại viên mãn mở truyền tống trận và giao nộp toàn bộ nguyên tinh — ánh mắt hắn khiến tông chủ tự phun máu mà không cần động thủ. Không kiên nhẫn chờ nửa canh giờ, Vương Lâm cưỡng ép nguyên lực kích hoạt truyền tống trận rồi cùng bà lão biến mất, trận pháp sụp đổ sau đó. Hắn để lại lời hứa bồi thường gấp mười lần."},{"chuong":1216,"tieuDe":"Uy Danh Mười Năm Trước","tomTat":"Vương Lâm cùng bà lão tóc bạc cưỡng ép ngưng tụ thiên địa nguyên lực vào truyền tống trận ở tinh vực cấp dưới để truyền tống tức thì lên tinh vực cấp sáu, phá nát truyền tống trận khi xuất hiện. Đệ tử Tiên Âm Môn trông coi trận pháp nhận ra hắn chính là Lữ Tử Hạo — kẻ tưởng đã bị Thần Tông giết mười năm trước. Vương Lâm lao tới ba đại lục Tiên Âm Môn, một chưởng phá tan toàn bộ đại trận phòng ngự mà tu sĩ Toái Niết cũng phải tốn thời gian mới phá nổi. Tông chủ tân nhiệm Tiên Âm Môn từng chứng kiến trận chiến năm xưa, không dám kháng cự, lập tức giao toàn bộ nguyên tinh và mở truyền tống trận hướng tới Vô Cực Tông. Vương Lâm thu nguyên tinh, cùng bà lão truyền tống tới tu chân tinh Vô Cực Tông tinh vực cấp tám, tuyên bố muốn lấy một thứ pháp bảo tại đây."},{"chuong":1217,"tieuDe":"Cường Giả Vi Tôn!","tomTat":"Vương Lâm quay lại Vô Cực Tông qua truyền tống trận, lao thẳng tới ngọn núi do thanh kiếm Cổ Thần hóa thành để đoạt pháp khí Cổ Thần cửu tinh nhằm cứu Lý Thiến Mai nơi chiến trường. Khi hắn kích hoạt Cổ Thần lực bên trong ngọn núi, mi tâm lần lượt tái hiện bốn Cổ Thần tinh điểm, pho tượng Cổ Thần bên trong giãy giụa gào thét, núi nứt vỡ thiên địa biến sắc. Sáu cường giả Thiên Nhân Đệ Nhất Suy của Vô Cực Tông lao tới ngăn cản: hắc y lão giả thi triển mười chín lôi cầu nhưng bị Vương Lâm giành quyền khống chế bằng một chữ «Lôi», tông chủ Vô Cực Tử dùng long kiếm tấn công nhưng bị ngàn vạn đạo kiếm khí đánh lui, hắc y lão giả phun máu. Vương Lâm cố thương lượng, hạ huyết thệ phun máu tạo ký hiệu chứa hồn phách gửi tông chủ, tiết lộ Thủy Đạo Tử giết hắn bất thành mà bị trọng thương bế quan. Hắc y lão giả chụp nát huyết thệ, thương lượng hoàn toàn thất bại. Vương Lâm lạnh lùng tuyên bố «cường giả vi tôn», chấp nhận dùng vũ lực. Bốn thái tổ trưởng lão Vô Cực Tông kéo đến trực tiếp tấn công."},{"chuong":1218,"tieuDe":"Một Câu Nói","tomTat":"Sáu trưởng lão thần thông Thiên Nhân Đệ Nhất Suy của Vô Cực Tông đồng loạt vây công Vương Lâm. Giữa trận chiến, Vương Lâm phát hiện ngọc bội mệnh hồn Lý Thiến Mai nứt thêm nửa tấc, mệnh hồn cực kỳ suy yếu, nàng đang gặp nguy cơ sinh tử. Trong cơn bức bách, Vương Lâm đột phá lên Lục tinh vương tộc Cổ Thần, tinh điểm thứ năm và thứ sáu đồng loạt hiện ra, tinh điểm thứ bảy bắt đầu hình thành. Hắn đạp sụp ngọn núi sơn môn Vô Cực Tông, thu thanh huyết kiếm Cổ Thần bị phong ấn bên trong — khi chạm vào cảm giác máu mủ tình thâm như vốn thuộc về hắn. Dồn sức mạnh Cổ Thần vào huyết kiếm chém một nhát, khiến hai trưởng lão mất nhục thân, bốn người trọng thương. Vương Lâm bay lên trời cảnh cáo Vô Cực Tông: nếu Quy Nguyên Tông bị tổn thương sẽ xóa tên Vô Cực Tông khỏi Vân Hải, rồi rời đi. Hắn ngộ ra rằng trong tu chân giới, một kiếm một câu nói mạnh hơn vạn lời hứa."},{"chuong":1219,"tieuDe":"Cái Khe Yêu Tông","tomTat":"Sau trận đánh bại sáu trưởng lão Vô Cực Tông, Vương Lâm thu huyết kiếm Cổ Thần vào mi tâm và tự đánh giá toàn diện sức mạnh hiện tại: ba thành uy lực huyết kiếm đủ chém chết Thiên Nhân Đệ Nhất Suy, chưa mở phong ấn dùng đạo thuật Đạo cảnh cũng đủ chiến ngang, nếu mở phong ấn có hy vọng đạt Toái Niết trung kỳ đối phó cả Đệ Tam Suy. Hắn xác lập mục tiêu rõ ràng: đạt Đệ Tam Bộ, giết Thủy Đạo Tử và lão tổ gia tộc thượng cổ La Thiên. Cùng lúc, Thủy Đạo Tử trong mật thất Thần Tông tầng thứ chín chịu thống khổ sinh tử mười năm, dung nhan biến đổi liên tục, đồng tử biến mất bị ánh sáng bảy màu che khuất, thề trả thù Vương Lâm và nhắc đến chủ nhân cực kỳ suy yếu. Vương Lâm khai phá tầng thứ tám, lần đầu bước vào tầng thứ chín Vân Hải tinh vực, phóng sát khí kinh động mãnh thú cấp mười hai, được lão bà áo trắng dẫn đường tới cái khe chiến trường Yêu Tông. Chương giới thiệu toàn diện Yêu Tông: tông phái thần bí nhất Vân Hải, ít môn nhân nhưng đáng sợ, tách từ Thần Tông mà không tuân lệnh, trường kỳ phòng thủ cái khe chống mãnh thú. Tại chiến trường, mấy nghìn tu sĩ đang chiến đấu, sáu cao thủ nổi bật trong đó có nữ tử lạnh như băng dùng kiếm vàng và lão già tu vi gần Đệ Nhất Suy. Ba người Yêu Tông thật sự đứng trong sương mù lam quan sát. Cuối chương, mãnh thú đồng loạt co rút, dấu hiệu vương thú xuất hiện, nữ tử lạnh như băng tuyên bố muốn giết vương thú, trong khi Vương Lâm đang ngày càng tới gần."},{"chuong":1220,"tieuDe":"Thân Ảnh Áo Trắng Trong Hồng Quang","tomTat":"Tại chiến trường khe nứt bên ngoài sáu tu chân tinh Yêu Tông, Cửu U Long — ấu long từ Cửu U Thâm Uyên, thực lực cấp mười hai, một trong sáu loài thú đồng hành thiên giai đạo thú Cát Cùng — xuất hiện. Ba tu sĩ Yêu Tông sương lam nhận dạng và truyền tin cấp báo trưởng lão. Sáu cao thủ liên thủ tấn công Cửu U Long nhưng thất bại trước đầu lâu nghìn trượng hút sức sống, bốn người bị thương nặng. Lão già tu vi cao nhất ra lệnh mấy nghìn tu sĩ hiến tế sức sống kích hoạt Yêu Tông đại trận, phong bế tạm thời khe chiến trường khiến Cửu U Long thu mình. Ba tu sĩ Yêu Tông tuyên bố sẽ tự đối phó Cửu U Long khi trận pháp hết nhưng bị gián đoạn: từ xa truyền đến tiếng gào thét kinh thiên, một đạo hồng quang ngợp trời lao tới. Bên trong có một nam tử áo trắng tóc bạc tu vi cường hãn khiến tinh không gợn sóng, phía sau có lão bà áo trắng đi theo."},{"chuong":1221,"tieuDe":"Trở Thành Vật Cưỡi Của Ta, Ta Sẽ Tha Mạng Cho Ngươi!","tomTat":"Chương giới thiệu chi tiết cấu trúc Yêu Tông với sáu tu chân tinh xếp hình tròn tạo đại trận, sáu sơn môn hoạt động độc lập, cùng truyền thuyết về tông chủ đời đầu — người theo lời đồn cũng chính là tông chủ Thần Tông, đến từ Viễn Cổ Tinh Vực, đã mất tích, hiện Thần Tông do người hầu năm xưa thay mặt điều khiển. Vương Lâm cùng Bạch Bà Tử bay từ tầng thứ hai tinh vực đến khe chiến trường, khí tức của hắn khiến mấy ngàn tu sĩ và sáu cao thủ chấn động, mãnh thú hoảng sợ. Vương Lâm vung tay tạo cuồng phong lôi đình quét sạch toàn bộ mãnh thú bên ngoài khe, nhận ra đầu lâu hắc khí mang khí tức ma đầu Tịch Diệt Giới liền há miệng hút hết. Không chờ trận pháp mở, Vương Lâm dùng hai tay xé rách khe chiến trường, Cửu U Long nghìn trượng lao ra cắn nuốt nhưng bị đánh hai chưởng — bị thương nặng và mất hai sừng. Vương Lâm giẫm lên đầu rồng yêu cầu nó làm vật cưỡi dẫn đường vào khe tìm Lý Thiến Mai."},{"chuong":1222,"tieuDe":"Đạo Thuật","tomTat":"Cửu U Long cảm nhận ba luồng khí tức trên người Vương Lâm — sức mạnh thần linh thái cổ, sức mạnh cắn nuốt hồn phách và khí tức thú hoàng Cát Cùng — rồi khuất phục dưới hai chưởng ấn, trở thành vật cưỡi. Toàn bộ tu sĩ bên ngoài khe nứt chấn động. Khi Vương Lâm định bay sâu vào khe nứt tìm Lý Thiến Mai, trưởng lão Yêu Tông tu vi Thiên Nhân Đệ Nhị Suy từ tu chân tinh ba bước dịch chuyển tinh không xuất hiện chặn đường, đòi thử tư cách. Hai bên giao đấu kịch liệt: Vương Lâm dùng sức mạnh Cổ Thần, hóa giọt máu mi tâm thành huyết kiếm chém nát pháp bảo mai rùa, rồi thu huyết kiếm vào thân hóa toàn thân thành kiếm, song chỉ tay phải phá hủy Dịch Linh Ấn hoàn chỉnh năm ký hiệu và điểm trán đánh đối thủ bay khỏi khe nứt. Trưởng lão xin dừng tay, thừa nhận là sư phụ năm xưa thu nhận Lý Thiến Mai, tặng ngọc giản bản đồ khe nứt có đánh dấu vị trí cô. Vương Lâm nhận bản đồ rồi cưỡi Cửu U Long bay sâu vào nơi tối đen. Trưởng lão kiểm tra bản thân phát hiện đạo niệm bị ngoại lực xâm nhập suy yếu — đây là đạo thuật Vương Lâm âm thầm thi triển trong lúc giao đấu; lão kinh hãi nhận ra trên thân Vương Lâm còn phong ấn chưa mở, lập tức trở về sơn môn bế quan."},{"chuong":1223,"tieuDe":"Manh Mối Của Lý Thiến Mai","tomTat":"Vương Lâm cưỡi Cửu U Long tiến sâu vào khe nứt chiến trường Yêu Tông — một thế giới tối đen khổng lồ tựa tinh không khác, chứa mấy vạn mãnh thú. Nhờ khí tức vương thú của Cửu U Long, mãnh thú không dám tới gần. Trên đường đi, hắn hồi tưởng mười năm trong Thiên Nghịch, nhờ huyết quang của Lý Thiến Mai mà không tiêu tan, từ đó tiến nhập Đạo cảnh và cảm ngộ được đạo thuật Mộng Đạo — thần thông thứ ba sau Tàn Dạ Lưu Nguyệt. Càng tiến sâu, thế giới chuyển từ đen sang tím, vào biên giới khu vực gọi là khe nứt Tử Giới, Cửu U Long run rẩy sợ hãi. Tại đây, Vương Lâm cảm nhận dao động thần thông còn sót lại — lần đầu tìm được manh mối về Lý Thiến Mai. Hắn thi triển Tuế Nguyệt Nghịch Chuyển đảo ngược thời gian, nhìn thấy ảo ảnh quá khứ: nữ tử áo lam sắc mặt nhợt nhạt, quần áo nhuốm máu, tay cầm trường kiếm, bút vàng vờn quanh, đang nhanh chóng bay đi trong hư vô."},{"chuong":1224,"tieuDe":"Tiếng Kêu Dài!","tomTat":"Vương Lâm nhận ra Lý Thiến Mai gầy yếu da bọc xương đang giao chiến với hư ảnh tiên tử trong khe nứt tím, kích động vui mừng điên cuồng. Hắn dùng thần niệm thúc Cửu U Long tiến sâu, nhưng Cửu U Long phát hiện khí tức băng hàn đáng sợ liền hoảng sợ dừng lại — nơi đây là cấm địa của nó. Vương Lâm lấy ngọc bội mệnh hồn ra thấy vết nứt lan rộng, mệnh hồn suy yếu, biết tính mạng Lý Thiến Mai nguy kịch, liền nhảy khỏi Cửu U Long tự mình xông vào. Hắn một mình tàn sát mãnh thú rùa trăm trượng, mãng xà nghìn trượng, nhện mặt người nghìn trượng bằng kiếm khí, lửa lam, lôi đình và Dịch Linh Ấn, thế như chẻ tre tiến tới cuối thông đạo. Tại vùng băng hàn sâu nhất, hắn triệu hồi hơn một vạn Văn thú từ khe nứt trữ vật giao chiến với mãnh thú bạch khí rồi tiếp tục tiến lên. Lý Thiến Mai đã dùng hết pháp bảo, trường kiếm tan vỡ, nguyên lực và đan dược cạn kiệt, chỉ còn cây bút màu vàng chống cự yếu ớt, lam quang bảo vệ sắp sụp đổ, tuyệt vọng nhắm mắt chờ chết. Ngay lúc đó, tiếng nổ kinh thiên kèm tiếng kêu dài từ xa truyền đến, nàng mở mắt không dám tin, nước mắt lại chảy xuống."},{"chuong":1225,"tieuDe":"Xông Ra!","tomTat":"Bên trong khe nứt thế giới màu tím, lam quang bảo hộ trên thân Lý Thiến Mai bị hư ảnh chiếc roi khổng lồ quất vỡ, mãnh thú lao tới tấn công nàng. Vương Lâm cảm nhận khí tức quen thuộc của Lý Thiến Mai, điên cuồng chém giết hơn vạn Văn thú mở đường máu. Hắn dùng Định Thân Thuật và Súc Địa Thành Thốn tiếp cận, tay không túm hư ảnh chiếc roi khi chỉ còn cách nàng bảy tấc, phun máu nhưng không lùi, kích phát tinh điểm Cổ Thần phá hủy chiếc roi. Lý Thiến Mai sức sống cạn kiệt, nguyên thần suy yếu, hồn phách bắt đầu tan rã, nói lời cảm ơn rồi nhắm mắt, cây bút vàng trong tay tan vỡ. Vương Lâm thi triển Tuế Nguyệt thần thông — thạch môn khổng lồ hiện ra, dòng Tuế Nguyệt chảy quanh thân nàng làm chậm quá trình tử vong nhưng phải duy trì liên tục. Hắn nhớ lại Lý Mộ Uyển năm xưa già đi trong vòng tay mình và người yêu đang ngủ trong Tị Thiên Quan. Đối mặt thêm hai hư ảnh chiếc roi và vô số mãnh thú bao vây, Vương Lâm quyết tâm mang Lý Thiến Mai xông ra, cào mi tâm mở phong ấn cấm chế phức tạp, giải phóng toàn bộ tu vi đã bị phong ấn ở Thất Thải giới hai ngàn năm trước, thể hiện tư thái cực mạnh."},{"chuong":1226,"tieuDe":"Mở Ra Phong Ấn!","tomTat":"Vương Lâm vì Lý Thiến Mai và ân nghĩa mười năm mà quyết mở phong ấn cấm chế trong cơ thể, giải phóng đạo quả từ thất thải giới đã bị áp chế suốt thời gian dài. Phong ấn sụp đổ, nguyên lực thiên địa điên cuồng chảy vào, tu vi từ Tịnh Niết đại viên mãn đột phá lên Toái Niết sơ kỳ. Hai hư ảnh chiếc roi từ hư vô tối đen lao tới tấn công — chiếc thứ nhất bị lốc xoáy đánh vỡ, chiếc thứ hai bị hắn túm lấy. Vương Lâm ngửa mặt rít gào khiến hơn trăm mãnh thú nổ tung thành sương máu, vương thú sợ hãi lùi lại. Đạo quả chưa tiêu hết, tu vi tiếp tục bạo tăng lên Toái Niết trung kỳ. Hắn ném chiếc roi đi rồi phun huyết quang hóa huyết kiếm phá hủy nó trong hư vô, tiếng kêu rên bí ẩn truyền ra. Khe nứt quỷ dị khiến Thiên Kiếp không thể giáng xuống, nếu ở bên ngoài Thiên Kiếp sẽ mạnh hơn vô số lần."},{"chuong":1227,"tieuDe":"Cấp Mười Ba","tomTat":"Vương Lâm đứng giữa biển máu nhận diện nữ tử áo đen thực chất là mãnh thú bọ cạp chín đuôi cấp mười ba đã hóa hình người, tu vi tương đương Thiên Nhân Đệ Nhất Suy, chính là thủ phạm đả thương Lý Thiến Mai. Hắn dùng huyết kiếm chém nát chín chiếc roi đuôi bọ cạp hư ảnh, rồi thi triển thần thông học từ Lỗ Phu Tử đánh ra chưởng ấn ngưng tụ thiên địa nguyên lực kết hợp sức mạnh Cổ Thần tràn ngập vạn dặm, buộc nữ tử phải phun máu phòng thủ. Nữ tử rút roi đuôi bọ cạp thực thể nhưng cũng bị huyết kiếm chặt đứt, buộc phải hiện nguyên hình bọ cạp khổng lồ vạn trượng. Vương Lâm kích hoạt tinh điểm Cổ Thần, biến thành hình thể Cổ Thần gần ngàn trượng, đánh bại hoàn toàn bọ cạp: phá nát hai càng, kéo đứt hai đuôi, quăng thân bọ cạp vào đàn mãnh thú khiến nó gần như tử vong. Chương xác nhận đây là trạng thái mạnh nhất trong hai ngàn năm tu đạo của Vương Lâm: Toái Niết trung kỳ, Cổ Thần tinh lục tinh (tinh điểm thứ bảy đã hiện hình), năm đạo bổn nguyên thức tỉnh, huyết kiếm máu Cổ Thần, đủ tư cách bá chủ một phương ở cả nội giới lẫn ngoại giới. Nữ tử bọ cạp dọa rằng Viễn Cổ Đế Phi sẽ giết toàn tộc Vương Lâm, hắn đáp lạnh lùng rằng toàn tộc đã chết, chỉ còn một mình. Sau đó Vương Lâm cầm đuôi bọ cạp làm vũ khí lao vào quét sạch đàn mãnh thú xung quanh, Văn Vương nhìn chằm chằm con bọ cạp sắp chết với vẻ khát máu."},{"chuong":1228,"tieuDe":"Tế Đàn Của Cổ Thần","tomTat":"Vương Lâm tiêu diệt bọ cạp chín đuôi cấp mười ba Tử Huyết, xé chín đuôi dung hợp thành một thu vào trữ vật, đập vỡ đầu lấy hắc đan chứa nguyên thần. Văn Vương dẫn năm nghìn Văn thú hút máu bọ cạp, tu vi tăng mạnh, rồi truy sát mãnh thú khắp khe nứt. Vương Lâm dùng thần thức lục soát ký ức bọ cạp, phát hiện khe nứt có mười chín mãnh thú hóa hình, càng sâu càng có mãnh thú cường đại, và nữ tử thần bí đang chữa thương bị giam cầm sâu bên trong. Hắn liên tưởng khe nứt này với khe nứt Phong Tiên giới nơi Văn Vương thoát ra, nảy ý dùng thiên kiếp giáng khi ra ngoài để phá đại trận Phong Giới. Khi sắp tới cửa ra, phân thân nữ tử áo hồng Y Nguyệt — phi tử viễn cổ Tiên Hoàng — bất ngờ xuất hiện, nhận ra huyết kiếm từng đả thương Tiên Hoàng và năm đạo bổn nguyên trong cơ thể Vương Lâm. Y Nguyệt đề nghị liên minh: đổi việc giúp Vương Lâm rời khe nứt cứu Lý Thiến Mai lấy hắn quay lại giúp nàng chữa thương, phần thưởng là dẫn hắn tới tế đàn Cổ Thần và kết đồng minh vĩnh viễn. Vương Lâm nhận ngọc bội truyền tống, kiểm tra an toàn rồi rời đi. Cuối chương, bản thể Y Nguyệt ngồi trong tinh thể lục giác mười trượng sâu trong khe nứt tối đen, chậm rãi mở mắt nhìn vào hư vô."},{"chuong":1229,"tieuDe":"Thiên Kiếp Giáng Xuống","tomTat":"Gần một tháng sau khi Vương Lâm tiến vào khe nứt chiến trường, khu vực bên trong trở nên quá mức yên tĩnh với mùi máu tanh liên tục tràn ra ngoài. Một lão giả đại cao thủ lẻn vào dò xét rồi quay về báo cáo: toàn bộ bên trong là thi thể mãnh thú bị phá nát gồm cả thú vương, hình thành biển máu. Các tu sĩ kinh hoàng suy đoán nguyên nhân, nhiều người không tin một mình Vương Lâm gây ra sát kiếp lớn đến vậy. Ngay sau đó, tầng mây tím cuồn cuộn bao phủ cả tinh vực cấp chín, uy áp mênh mông khiến hàng trăm tu sĩ phun máu — thiên kiếp giáng xuống. Thái thượng trưởng lão Yêu Tông lần đầu lộ diện, nhận ra đây là vô lượng kiếp — tất sát chi kiếp dành cho người bằng với thiên địa. Hắn ra lệnh mở trận pháp sơn môn, đón tất cả tu sĩ vào tu chân tinh trú ẩn. Trong tầng mây mở ra lỗ hổng thông thế giới khác, hiện ra tòa lầu các bạch ngọc với pho tượng ngồi khoanh chân và hai thanh thạch kiếm cắm trước người."},{"chuong":1230,"tieuDe":"Một Tay Che Trời","tomTat":"Thiên kiếp bùng nổ khắp tinh vực cấp chín, tiếng sấm lan tới cả tinh vực cấp tám, đại lục hoang dã sụp đổ, vô số mãnh thú chết. Vương Lâm mặc y phục đỏ đẫm máu xuất hiện từ khe nứt chiến trường Yêu Tông, tay phải che chở Lý Thiến Mai, tay trái giơ lên đỡ tia sét ngàn trượng rồi tranh đoạt quyền điều khiển lôi lực thiên địa, phản kích lôi đình oanh thẳng vào tầng mây. Ý chí của hắn theo lôi đình xâm nhập mật thất Thần Tông, kích hoạt Thất Thải Đinh tỏa sáng chói mắt khiến Thủy Đạo Tử phun máu, toàn bộ công sức ép gỡ pháp bảo uổng phí. Mộc Băng Mi bị giam mười năm trong Thần Tông bừng tỉnh từ đả tọa, Vương San San tái mặt bên cạnh. Tông chủ Phá Thiên Tông rời bế quan mở đại trận rồi hướng về khe nứt Yêu Tông. Quỷ Tông mở đại trận, hư ảnh yêu thần vạn trượng tham lam hút lực lượng kỳ dị từ tầng mây. Vương Lâm nhìn xuyên tầng mây thấy lầu các bạch ngọc với pho tượng và hai thanh thạch kiếm ở thế giới bên kia, nhận định thiên kiếp chưa đủ phá đại trận Phong Giới. Thanh thạch kiếm thứ nhất phóng khí xanh hóa hư kiếm tấn công, Vương Lâm dùng kiếm khí hư ảnh hươu chống đỡ, hư kiếm suy yếu nhưng thạch kiếm nứt vỡ phóng ra trường kiếm xanh thật sự lao về phía hắn."},{"chuong":1231,"tieuDe":"Phong Giới Đại Trận","tomTat":"Huyết kiếm đã hấp thu máu mãnh thú trong thế giới khe nứt xuất hiện trong tay Vương Lâm, lần lượt đối đầu bốn thanh kiếm thiên kiếp (xanh, lam, đen, vàng) vỡ ra từ thạch kiếm trước pho tượng trên lầu các bạch ngọc mà không hề suy xuyển. Vương Lâm rạch Cổ Thần tinh điểm lấy giọt máu Cổ Thần lực tiếp cho huyết kiếm, triệu hồi hư ảnh hình người đẩy lùi ba kiếm. Bốn kiếm thiên kiếp xoay tròn tạo dòng xoáy chứa thế giới hỗn độn, phát tiếng gọi mê hoặc hứa trường sinh thoát luân hồi, hút hàng trăm tu sĩ Yêu Tông cùng tu sĩ Thần Tông, Phá Thiên Tông biến mất. Vương Lâm là người ứng kiếp nên cảm thụ mạnh hơn — tiếng nói biến thành giọng phụ mẫu, Lý Mộ Uyển, Vương Bình, Chu Tước lão Thánh Hoàng — nhưng đạo tâm kiên cố không lay động. Dòng xoáy tiêu tán vào tầng mây ngưng tụ thành núi mây tím khổng lồ có phù văn chữ đạo đè xuống. Chờ đúng lúc thiên kiếp triển khai toàn bộ uy lực, Vương Lâm dùng huyết kiếm xé tinh không phía dưới, kết hợp tu vi và áp lực núi mây mở khe nứt vào hư vô nơi Phong Giới Đại Trận. Bước vào hư vô, hóa thành lạc ấn, dùng thân chống đỡ núi mây, phun máu truyền lực thiên kiếp lên đại trận dạng lưới — trở thành người đầu tiên từ cổ chí kim mượn thiên kiếp phá phong ấn Phong Giới."},{"chuong":1232,"tieuDe":"Cửu Cung Bát Quái","tomTat":"Vương Lâm triệu hư ảnh Cổ Thần truyền lực vào Phong Giới đại trận, kích phát hào quang bảy màu biến ảo thành trường thương bạch ngọc xuyên thấu núi mây Thiên Kiếp, lộ ra bốn thanh bảo kiếm bên trong. Hắn phun máu vì thương thế nhưng kiên định, nhớ lại tiếng gào không cam lòng của tu sĩ giới nội chết trên Phong Giới đại trận từ xưa, khơi dậy huyết tính. Khe nứt tinh không xé rộng, pho tượng trên lầu các bạch ngọc tỉnh dậy — tay phải biến từ đá thành máu thịt, hô Cửu Cung Vô Lượng phát chín tinh cầu Cửu Cung Phong Ấn giáng xuống. Chín thiên thạch cổ đại nhập thể Vương Lâm qua chín đốm máu, cố ngưng tụ ở ngực để phong ấn. Vương Lâm hóa Lục tinh Cổ Thần cao nghìn trượng, giấu Lý Thiến Mai trên người, dùng sức Cổ Thần ngăn ngưng tụ và tuyên bố mình là Cổ Thần không phải tiên. Pho tượng tiếp tục phát động Bát Quái Ấn mạnh hơn Cửu Cung, tám ký hiệu tạo vòng tròn biến hóa đè xuống khiến Vương Lâm buộc phải lui bước. Trong tình thế nguy cấp, hắn bình tĩnh gọi chủ nhân Phong Giới xuất hiện, tiết lộ đã bí mật đưa người này tới đây từ trước."},{"chuong":1233,"tieuDe":"Thiên Kiếp Là Kiếp, Chỉ Vì Tạo Hóa","tomTat":"Vương Lâm truyền thần niệm kích hoạt Thiên Nghịch Châu, từ bên trong nguyên thần biến ảo ra ngọc bội của chủ nhân Phong Giới (Tông Chủ) bay khỏi cơ thể, khiến Bát Quái Thiên Kiếp chấn động. Thái thượng trưởng lão Yêu Tông Huyền Bỉnh nhận ra ngọc bội, phá khai đại trận xuất hiện. Ngọc bội biến ảo ra cây đại thụ chọc trời hiện mặt người Tông Chủ, lần lượt ra mệnh lệnh: giao Huyền Bỉnh dùng đạo khí sửa sang Vân Hải Tinh Vực và đi tìm Nam Vân Tử, Hồng Sam Tử, Chiến Tiên Tử để hợp nhất Tứ Đại Tiên Giới Phong Vũ Lôi Điện chuẩn bị đại chiến giới ngoại; lệnh Thủy Đạo Tử toàn lực trợ giúp Yêu Tông; nhắc Cổ Yêu thực hiện ước định năm đó. Tông Chủ hé lộ bản chất Thiên Kiếp cho Vương Lâm: đến từ thái cổ, từ thiên đạo sinh tử, hiện tại chỉ là Tiểu Kiếp. Ngọc bội hóa tinh quang phá giải Phong Giới Đại Trận. Vương Lâm nhớ lời Thanh Thủy về Cực Cảnh, liều mạng để Bát Quái dung nhập cơ thể nhờ thân Cổ Thần chống chịu. Thiên Kiếp tiếp tục giáng Thất Tinh Bắc Đẩu sát kiếp, Bát Hoang Phong Thiên Trận phong tỏa mọi đường lui, và Ngũ Hành vô lượng năm thủ ấn khổng lồ lao tới."},{"chuong":1234,"tieuDe":"Cực Cảnh Sinh Ra","tomTat":"Vương Lâm ngộ ra bản chất thiên kiếp diễn biến từ chín tới một, tầng tầng hợp nhất cuối cùng thành thiên cực kiếp — Cực Cảnh. Hắn từ chối thái thượng trưởng lão Yêu Tông trợ giúp, tuyên bố phải tự mình đối kháng. Bị Thất Tinh đánh trọng thương, nguyên thần sụp đổ nhưng khóa chặt, chủ động nuốt hỏa chưởng ấn Ngũ Hành để tái tạo nguyên thần, dùng Ly hỏa và Chấn lôi phản kháng. Tứ Tượng thiên kiếp triệu tứ linh, Vương Lâm thu phục Chu Tước nhập thể, hỏa diễm gần đạt hư hỏa chỉ kém một đường. Tam Tài giáng xuống xuyên thấu mi tâm, ngực, tứ chi. Lưỡng Nghi hóa Thái Cực phát nổ bao trùm toàn thân, thân Cổ Thần lục tinh huyết nhục mơ hồ — Lý Thiến Mai được bảo vệ không tổn thương. Cuối cùng Nhất Kiếp tuyên vô lượng kiếp bắt đầu, Cửu Cung tới Lưỡng Nghi đồng loạt xuất hiện sinh ra Cực Cảnh, đồng thời Cực Cảnh cũng sinh ra bên trong cơ thể Vương Lâm."},{"chuong":1235,"tieuDe":"Thôn Linh Phệ Thể Tuyệt Thiên Đại Pháp!","tomTat":"Trong vô lượng kiếp, chín thiên thạch Cửu Cung biến ảo xếp thành đồ án chồng lớp từ Bát Quái tới Thái Cực đồ, cuối cùng sinh ra Cực Cảnh — đồng thời cơ thể Vương Lâm cũng tái sinh Cực Cảnh đã mất ngàn năm, tóc bạc chuyển đỏ, thân ngừng sụp đổ. Vương Lâm dùng hai đạo Cực Cảnh kết hợp sợi tơ xanh của chủ nhân Phong Giới phá một lỗ hổng nhỏ trên Phong Giới Đại Trận, thu nhỏ thân Cổ Thần ôm Lý Thiến Mai lao ra Thái Cổ Tinh Thần — chính thức đặt chân vào giới ngoại. Ngay khi thoát ra, Khai Thiên Phủ phản chủ lao theo chém xuyên ngực Vương Lâm gây trọng thương cực nặng, rồi dung nhập Phong Giới Đại Trận biến mất, lỗ hổng khép lại với sợi tơ xanh kết rễ. Đối diện mấy trăm tu sĩ giới ngoại xông tới giết, Vương Lâm nhớ lời nguyền của tiền bối Thất Thải Giới, lần đầu thi triển tiên thuật Thôn Linh Phệ Thể Tuyệt Thiên do Thanh Thủy truyền — bắt quyết điểm ngực, hóa sương mù đen nuốt sạch tinh hoa tu sĩ để chữa thương, bắt đầu tàn sát."},{"chuong":1236,"tieuDe":"Thác Sâm","tomTat":"Vương Lâm ẩn trong sương mù đen, dùng Thôn Linh Phệ Thể Tuyệt Thiên điên cuồng thôn phệ mấy trăm tu sĩ giới ngoại đang thủ trận tại Phong Giới Đại Trận. Lão giả Toái Niết đại viên mãn chỉ huy kết trận, thi triển thần thông ngũ sắc và tấm khiên mặt quỷ chống đỡ nhưng bị tia chớp đỏ xuyên phá tất cả, nguyên thần diệt tuyệt, xác hóa tro. Vương Lâm tiếp tục thôn phệ liên tục, hóa sương mù thành dòng xoáy hút tu sĩ chạy xa trở lại, quét sạch toàn bộ không còn sống sót. Tu vi cấp tốc khôi phục, nguyên thần no đủ, nhưng vết thương ngực vẫn chậm lành. Cảm giác thôn phệ giống ăn tiên quả, gây mê muội không nỡ dừng — hắn lộ dấu hiệu ma hóa rõ ràng, bị tu sĩ giới ngoại gọi là ma. Chương nhắc lại hàng ngàn năm trước, tiên nhân giới nội cố phá Phong Giới Đại Trận thoát ra nhưng bị trận linh giết chết, giới ngoại lạnh lùng đứng nhìn — tiên nhân trước khi chết thề đời sau sẽ phá trận khiến giới ngoại vạn linh tuyệt diệt. Cuối chương Vương Lâm cảm ứng nguy hiểm, thôn phệ nốt tu sĩ rồi dùng súc địa thành thốn biến mất, ngay lúc đó một thân ảnh khổng lồ sánh với tinh không gầm thét tên Vương Lâm lao tới."},{"chuong":1237,"tieuDe":"Truy Sát","tomTat":"Vương Lâm dung nhập trời đất thoát khỏi tầm mắt Thác Sâm ở giới ngoại Thái Cổ Tinh Thần. Thác Sâm đã đồ sát bộ lạc thái cổ suốt mười năm nên bị ba cao thủ bước thứ ba (một người cảnh giới Không Niết) truy sát, bị thương nghiêm trọng và yếu đi nhiều. Thác Sâm cảm nhận khí tức Vương Lâm, xé tinh không đuổi theo, hai bên đối đầu ngắn ngủi — Vương Lâm dùng Cực Cảnh (thiên kiếp cực) tấn công, tia chớp đỏ chui vào cơ thể Thác Sâm phá hoại liên tục, nhưng bị Thác Sâm phản đòn đánh trúng, phun máu, vết thương ngực chứa khí tức Khai Thiên Phủ lại toạc ra. Ba cao thủ bước thứ ba kịp thời ép tới ngăn Thác Sâm truy kích, Vương Lâm thoát được. Sau khi bình tĩnh lại, Vương Lâm xác định mục tiêu đưa Lý Thiến Mai tới chỗ Lam Mộng Đạo Tôn — ngũ đại tôn giả Thái Cổ Tinh Thần ở Lam Sơn (Lam Ti Tộc). Hắn quyết tâm giết tu sĩ giới ngoại chuẩn bị cho đại chiến hai giới, tấn công Ma Nạp Tinh, dùng sương đen nuốt toàn bộ tu sĩ, dùng thuật Định và Cực Cảnh hạ lão giả áo xanh lục (thiên nhân đệ nhất suy) mạnh nhất trên tinh."},{"chuong":1238,"tieuDe":"Liên Hệ","tomTat":"Vương Lâm hiện thân trên tu chân tinh, dùng sương đen diệt gần như toàn bộ tu sĩ ngoại giới, sau đó thi triển Trừu Tinh Hồn Lực rút tinh hồn toàn hành tinh. Hắn tiếp tục bay qua nhiều tu chân tinh khác thu tổng cộng bảy đám khí tinh hồn, nguyên thần hồi phục gần hết, chỉ còn vết thương do Khai Thiên Phủ vẫn chưa lành. Nhận định chỉ sức mạnh Cổ Thần mới bức được khí tức Khai Thiên Phủ, hắn quyết định hướng tới Nguyệt Tộc — thế lực Cổ Thần duy nhất hắn biết trong Thái Cổ Tinh Thần, đồng thời tính kế dẫn Thác Sâm đến nếu bị truy kích. Vương Lâm hồi tưởng toàn bộ cục diện nội-ngoại giới: Phong Giới Đại Trận hấp thụ hương hỏa khiến nội giới thiếu tu sĩ bước thứ ba, Chủ nhân Phong Giới bị Thủy Đạo Tử đánh lén và Chưởng Tôn liên thủ trọng thương, rồi chọn dung nhập vào Phong Giới Đại Trận biến nó thành vật nội giới. Chủ nhân Phong Giới nhìn thấy năm đạo bổn nguyên trên người Vương Lâm mà nhận làm truyền nhân, giao sứ mệnh thống lĩnh nội giới chống ngoại giới. Vương Lâm khẳng định Thái Cổ Tinh Thần không thuộc về hắn, hắn từ nội giới đến. Cùng lúc, Thác Sâm xé khe tinh không lao ra, bị ba cao thủ bước thứ ba Thái Cổ Tinh Thần truy sát mười năm; nhận ra không giết ba người này thì không thể cắn nuốt Vương Lâm, hắn hóa Cổ Thần khổng lồ quay đầu tuyên chiến."},{"chuong":1239,"tieuDe":"Trận Chiến Định Mệnh","tomTat":"Thác Sâm không tiếc cho nổ một tinh điểm để thoát khỏi ba cao thủ Viễn Cổ Tinh Thần truy sát, phong ấn nữ tử Không Niết rồi xé tinh không đuổi theo Vương Lâm. Hai cao thủ còn lại nhận thưởng lục phẩm đạo linh từ một nữ tử áo trắng bí ẩn mang khí tức Tiên Vực, người này sau đó lặng lẽ đi theo hướng Thác Sâm truy đuổi. Vương Lâm chủ động dẫn Thác Sâm vào lãnh địa Nguyệt Tộc, hóa thân Cổ Thần ngàn trượng giao phong chính diện, dùng huyết kiếm, Thần Quyền, Dịch Linh Ấn và lời uy hiếp về Đồ Ti thức tỉnh để chặn đứng ý định thôn phệ của Thác Sâm. Nguyệt Tộc chớp thời cơ kích hoạt Phong Thần Đại Trận chuẩn bị vô số vạn năm cùng hàng loạt chí bảo chuyên trị Cổ Thần, phong ấn cả hai bên. Vương Lâm thuyết phục Thác Sâm tạm hợp tác, cùng thi triển Cổ Thần Bát Tinh thuật Hư quét sạch pháp bảo Nguyệt Tộc, nhưng bị đốt xương ngón tay Cổ Thần gần cửu tinh đánh vỡ ký hiệu khiến cả hai trọng thương. Vương Lâm thi triển Thôn Linh Phệ Tuyệt Thiên nuốt hơn ba vạn tộc nhân khôi phục thương thế, rồi dùng Cổ Thần lực đã bí mật hút giữ từ Thác Sâm để thi triển thần thông Dòng chảy tinh thần, chém đứt ngón trỏ Thác Sâm bằng huyết kiếm và chẻ đôi đốt xương Cổ Thần khiến lực trùng kích quét ngang toàn trường. Nữ tu bước thứ ba phong ấn trong mi tâm Thác Sâm đột nhiên bộc phát ánh sáng chói mắt khiến hắn hoảng hốt bỏ chạy với một nửa đốt xương, còn Vương Lâm dùng Côn Cực Tiên cuốn bắt nguyên thần lão giả tóc bạc Nguyệt Tộc, mang theo nửa đốt xương còn lại rời khỏi tinh vực Nguyệt Tộc với thu hoạch khổng lồ."},{"chuong":1240,"tieuDe":"Đưa Nàng Cho Ta","tomTat":"Vương Lâm thoát khỏi cuộc đuổi giết của Thác Sâm sau khi mi tâm hắn dị biến tỏa sáng chói mắt khiến Thác Sâm bỏ chạy. Hắn lảo đảo xuất hiện trong tinh không Thái Cổ Tinh Thần, lấy Lý Thiến Mai ra từ khe trữ vật, dùng Tuế Nguyệt thần thông duy trì sinh cơ cho nàng đang sắp tiêu tán. Thu nửa đốt xương ngón tay Cổ Thần và dùng Côn Cực Tiên phong ấn lão giả tóc bạc vào trữ vật. Ôm Lý Thiến Mai bay xuyên tinh không hướng về Lam Ti tinh vực tìm Lam Mộng Đạo Tôn cứu chữa, nhớ lại lời hứa năm xưa với nàng và với Lý Mộ Uyển. Lam Ti tộc được giới thiệu lịch sử: tộc lạc tóc lam từng bị áp bức làm sủng cơ, sau được Lam Mộng Đạo Tôn quật khởi trở thành đại tộc. Lam Mộng Đạo Tôn — ngũ tôn Thái Cổ Tinh Thần, si tình chỉ yêu một nữ tử — gảy cổ cầm trên Lam Sơn, khẳng định với em gái người yêu rằng tỷ tỷ chưa chết. Bạch y nữ tử theo Vương Lâm tới bờ tinh vực Lam Ti tộc nhưng bị Lam Mộng Đạo Tôn chặn xua đuổi bằng ý cảnh tuyệt sát, nàng cảnh cáo rằng Vương Lâm đã bị lựa chọn rồi và sẽ phải đi ra. Cuối chương Vương Lâm ôm Lý Thiến Mai tới Lam Ti tinh vực, ánh sáng lam tràn ra và có tiếng nói trầm thấp vang vọng."},{"chuong":1241,"tieuDe":"Nối Lại…","tomTat":"Lam Mộng Đạo Tôn xuất hiện trong ánh lam quang, vung tay áo tạo gió lốc cướp lấy Lý Thiến Mai từ tay Vương Lâm rồi biến mất, từ đầu đến cuối không thèm liếc hắn một cái. Vương Lâm nhận ra giọng nói này chính là kẻ đã gây tai ương cho hắn ở Thất Thải Giới năm xưa, và đoán chắc Đạo Tôn là phụ thân của Lý Thiến Mai, có cách khiến nàng tỉnh lại. Hắn bay vào tu chân tinh của Lam Mộng Đạo Tôn, vận toàn bộ nguyên lực và Cổ Thần lực đối kháng trận pháp cấm chế kinh thiên trên Lam Sơn, leo bậc thang suốt ba ngày đêm, mồ hôi lẫn máu, mạch máu gần nổ tung, chỉ để nhìn thấy Lý Thiến Mai lần cuối trước khi rời đi. Trên đỉnh núi, Lam Mộng Đạo Tôn đã trục hết hắc khí từ thất khiếu Lý Thiến Mai, nàng khôi phục dung mạo và tỉnh lại, nhưng mất toàn bộ trí nhớ, tự xưng là Lam Nguyệt và hỏi Vương Lâm là ai. Vương Lâm đau khổ đáp tên mình rồi buông bỏ sự chống cự, bị lực cản đẩy tung khỏi đỉnh núi, khoảng cách kéo ra vô tận. Lam Nguyệt dù quên hết nhưng mơ hồ cảm thấy đau lòng và quen thuộc khi nhìn hắn bay đi, hỏi phụ thân tại sao lại có cảm giác đó. Lam Mộng Đạo Tôn nói khoảng cách xa nhất trên đời là lãng quên, đoạn tình cảm này vốn sai lầm, nhưng nếu sau khi mất trí nhớ mà hai người vẫn bắt đầu lại được thì hắn tuyệt sẽ không ngăn cản, dù phải đánh một trận với viễn cổ tiên vực."},{"chuong":1242,"tieuDe":"Bạch Y Nữ Tử","tomTat":"Vương Lâm rời Lam Sơn một mình trong tâm trạng bi thương, để Lý Thiến Mai ở lại. Khi Na Di tới biên giới tinh vực Lam Ti tộc, hắn bất ngờ cảm nhận nguy cơ sinh tử mãnh liệt chưa từng có kể từ Thủy Đạo Tử. Hắn thi triển ánh mắt ác mộng bằng năm đạo bổn nguyên trong đồng tử ở trình độ gần tới vô hạn, phát hiện một bạch y nữ tử không có sinh cơ tung bay trong tinh không, thần thức không thể cảm nhận, ánh sáng che kín tướng mạo. Sau khi đả tọa bảy ngày phân tích, Vương Lâm nhận ra nữ tử đã bám theo hắn từ sau khi gặp Thác Sâm, chỉ dừng ở ranh giới Lam Ti tộc. Hắn phát hiện thân thể mình đã biến hóa nhờ leo Lam Sơn: nguyên lực tăng, Cổ Thần lực hùng hậu hơn, nguyên thần linh hồn nhạy cảm hơn nhiều, và suy đoán Lam Mộng Đạo Tôn dùng cách gián tiếp ám chỉ cảnh báo vì không thể nói thẳng. Vương Lâm quyết định ở lại tu chân tinh thổ nạp một tháng, khôi phục tu vi tới đỉnh phong. Cuối chương, Lam Mộng Đạo Tôn hiện thân trong ánh sáng lam nhu hòa, hỏi Vương Lâm có muốn học chín đại thần thông của mình không."},{"chuong":1243,"tieuDe":"Lựa Chọn","tomTat":"Lam Mộng Đạo Tôn đưa ra hấp dẫn cực lớn cho Vương Lâm: truyền toàn bộ pháp thuật cả đời (chín thức thần thông, sáu thức tiên pháp, ba thức đạo thuật, một thức sinh tử), hương hỏa hai ngàn triệu môn đồ, năm đạo khí thiên thạch thiên ngoại, giúp thân thể Cổ Thần đại thành và bảy đạo bổn nguyên đại thành. Đổi lại hai điều kiện: ăn vong tâm quả phát thề thoát ly giới nội trở thành người Thái Cổ Tinh Thần, và cắt đứt tình cảm giới nội kết đạo lữ với nữ nhi duy nhất Nguyệt Nhi. Vương Lâm nhớ tới tiên nhân hy sinh trong Phong Giới Đại Trận và lời hứa cả đời với Lý Mộ Uyển, dứt khoát cự tuyệt. Hắn phản vấn Lam Mộng về người trọng yếu nhất, khiến đối phương trầm mặc, rồi chỉ ra giới nội tồn tại lực lượng khiến chưởng tôn hoảng sợ — Lam Mộng thừa nhận. Lam Mộng tiết lộ bước thứ ba tu đạo gồm tứ cảnh Không (Không Niết, Không Linh, Không Huyền, Không Kiếp), chưa ai độ kiếp Không Kiếp thành công, bản thân có hai đạo bổn nguyên ở mức Không Huyền đỉnh phong, giới ngoại ít nhất bảy người ngang hàng. Cuối cùng Lam Mộng không cưỡng cầu, xóa nhân quả và truyền cho Vương Lâm ba thức thần thông: Phiên Thiên Ấn (lật thiên địa đồ diệt vạn linh), thuật phòng ngự ánh sáng (cảm ngộ Không Linh), và thức thứ ba — một trong tam đại đạo thuật — chương kết thúc trước khi thi triển."},{"chuong":1244,"tieuDe":"Dung","tomTat":"Lam Mộng Đạo Tôn truyền thức thứ ba cho Vương Lâm — Dung biến đạo thuật, thần thông dung hợp thay đổi bổn nguyên bản thân, biểu diễn biến mây thành băng kiếm bảy thước. Vương Lâm thi triển Hô Phong đạo và Vũ đạo để Lam Mộng dung hợp giúp thành một giới phòng hộ, Hô Phong che trời Hóa Vũ phủ đất, lực phòng hộ tương đương Quang ảnh thuẫn. Lam Mộng xác nhận đây là lục đạo tam trọng thuật của tiên đế Bạch Phàm, Chí tôn Lôi giới. Trước khi rời đi, Lam Mộng Đạo Tôn bày tỏ quyết tâm: sẵn sàng phản bội Lam Ti tộc và Thái Cổ Tinh Thần nếu giúp nàng khôi phục trí nhớ. Vương Lâm bế quan bốn tháng trên đỉnh núi tu chân tinh, ngồi bất động dưới mưa gió sấm chớp, cuối cùng lĩnh ngộ thành công Phiên Thiên Ấn — lật trời thành đất, uy lực hủy thiên diệt địa vượt xa mọi thần thông cũ. Hắn còn nhận ra Phiên Thiên Ấn có biến thức nghịch chuyển da và nội tạng thân thể, sát thương mạnh hơn vô số lần. Lam Mộng Đạo Tôn trên Lam Sơn kinh ngạc vì người có năm đạo bổn nguyên chỉ mất bốn tháng đã học xong, trong khi hắn tưởng phải mất mấy năm."},{"chuong":1245,"tieuDe":"Bức Tường Ngăn Cách Bước Thứ Ba","tomTat":"Trên tu chân tinh Lam Ti Tộc, sau mùa mưa nửa năm chuyển sang mùa đông lạnh giá, Vương Lâm vẫn khoanh chân ngồi trên đỉnh núi phủ tuyết cảm ngộ tam đại thần thông. Sau khi đã hiểu Phiên Thiên Ấn, hắn dành bốn tháng lần mò Quang Ảnh Thuẫn — tản thần thức bao trùm toàn bộ tu chân tinh, nhìn thấy ánh sáng (sức sống) từ vạn vật ngưng tụ quanh thân hóa quang ảnh khổng lồ, nhưng chưa hoàn toàn minh ngộ do cảm nhận được bức tường ngăn cách — chính là cửa ải tiến vào bước thứ ba. Vương Lâm chuyển sang cảm ngộ đạo thuật dung hợp ẩn trong tiểu cầu lốc xoáy, dùng năm đạo bổn nguyên hấp thu hết khí bên trong cho đến khi tiểu cầu hoàn toàn tiêu tan. Hắn lần đầu thi triển đạo thuật dung hợp lên thanh kiếm băng, biến kiếm thành mảnh băng, nước mưa, sương mù rồi đám mây trắng bay đi. Vương Lâm quyết định dung hợp Súc Địa Thành Thốn trước để khắc phục khuyết điểm không thi triển được khi nguyên lực rối loạn. Hắn xác nhận kế hoạch cần hương hỏa Hỏa Tước Tộc và sấm sét Thiểm Lôi Tộc để năm đạo bổn nguyên đại thành, nhận ra ấn ký Thái Cổ Tinh Thần trên mi tâm có thể cắn nuốt lẫn nhau tiến hóa, và dự định tra nguyên thần trưởng lão Nguyệt Tộc để biết Chưởng Tôn thuộc bộ tộc thái cổ nào."},{"chuong":1246,"tieuDe":"Dị Biến!","tomTat":"Sau mấy tháng nhập định trên đỉnh núi Lam Ti Tộc, Vương Lâm dung hợp thành công Súc Địa Thành Thốn với cơ thể, lấy bản thân làm trời đất để bù sơ hở khi thiên địa nguyên lực hỗn loạn, nhưng nhược điểm mới là tiêu hao nguyên lực nhiều, chỉ thi triển liên tục hơn mười lần phải bổ sung. Hắn rà soát toàn bộ thần thông bình sinh và nảy ý dung hợp thêm Rải Đậu Thành Binh vào Hô Phong Hoán Vũ. Vương Lâm thử ép dung hợp Phong Tiên Ấn vào tiểu cầu lốc xoáy Hô Phong Hoán Vũ nhưng hai thứ bài xích dữ dội gây bùng nổ kinh thiên, hắn dùng Súc Địa Thành Thốn mang vụ nổ ra biên giới tinh vực rồi kích hoạt Quang Ảnh Thuẫn phản xạ sức hủy diệt để thoát hiểm. Không cam lòng, hắn đổi phương pháp: bóp nát tiểu cầu mở ra giới ngàn trượng Hô Phong Hoán Vũ rồi đưa Phong Tiên Ấn vào, nhưng sức bài xích vẫn khiến Phong Tiên Ấn nứt rạn rồi sụp đổ tan thành từng mảnh. Dị biến bất ngờ xảy ra: cấm chế bên trong Phong Tiên Ấn dung nhập vào giới hình thành một vùng thiên địa, vô số chiến hồn tản ra hóa tinh quang rơi vào từng mảnh vỡ, khiến Vương Lâm ngây người."},{"chuong":1247,"tieuDe":"Hương Hỏa","tomTat":"Giới ngàn trượng co rút dung nhập vào cơ thể Vương Lâm, hoàn thành dung hợp Hô Phong Hoán Vũ. Trở về tu chân tinh, hắn phát hiện chiến hồn trên các đại lục trôi nổi trong giới tản ra khí tức trắng sữa — hương hỏa thật sự — dung nhập năm đạo bổn nguyên. Vương Lâm nhận ra chuỗi nhân quả tạo hương hỏa: mảnh vỡ Lôi Tiên Giới qua Thiên Kiếp luyện hóa, dùng Rải Đậu Thành Binh tạo mười tám tầng địa ngục thu hồn phách, Lam Mộng Đạo Tôn trợ giúp dung hợp thành một giới mở ra cơ hội. Hắn lấy nửa đốt ngón tay Cổ Thần ra thử dùng tinh điểm hấp thụ nhưng thất bại vì ý chí bên trong chống lại. Sau đó lấy nguyên thần lão già tóc bạc Nguyệt Tộc từ Côn Cực Tiên, dùng huyết kiếm tra tấn suốt mấy canh giờ hút tinh khí, rồi dùng thần thức khai thác ký ức thần thuật và hủy diệt hoàn toàn. Hồn phách lão già hiện ra trong giới, tản ra hương hỏa kinh người. Từ ký ức, biết Nguyệt Tộc còn ba bộ lạc và một lão tổ tông bước thứ ba đang bế quan trị thương. Vương Lâm quyết định rời đi vì nữ tử áo trắng Lam Ti Tộc vẫn đợi bên ngoài."},{"chuong":1248,"tieuDe":"Ra Khỏi Lam Ti!","tomTat":"Vương Lâm khai thác trí nhớ lão già đốt ngón tay Cổ Thần, biết được Nguyệt Tộc vốn là Nô Tộc của Cổ Thần, nổi loạn nhờ đám người thần bí trợ giúp tự xưng Nguyệt Phệ Tộc, được truyền Thanh Vân Linh Thuật và Linh Chủng để hấp thụ sức mạnh Cổ Thần mà phát triển thành đại tộc. Thu đốt ngón tay Cổ Thần vào khe trữ vật rồi rời tinh vực Lam Ti Tộc bằng Súc Địa Thành Thốn. Nữ tử áo trắng đã đợi sẵn ngoài tinh không, hai lần phá gợn sóng Thuấn Di phong tỏa Vương Lâm, dùng bàn tay hư ảo bắt giữ rồi tự xưng Lan Phi, Lâu Lan, Viễn Cổ Bát Phi, lộ dung mạo trùng khớp Lý Mộ Uyển. Vương Lâm cố ý giả hoảng hốt để dụ nàng lộ mục đích hấp thu thần tính Cổ Thần, rồi bùng Hô Phong Hoán Vũ Giới đẩy lùi nàng ngàn trượng, dùng huyết kiếm phá bàn tay hư ảo thoát vây, thu lại làn khói vàng thần tính. Vương Lâm nhận ra nàng chỉ là phân thân, tuyên bố bản thể tới mới không địch nổi, rồi thi triển Phiên Thiên Ấn nghịch chuyển tinh không phản kích."},{"chuong":1249,"tieuDe":"Hình Chiếu Phân Thân","tomTat":"Vương Lâm thi triển Phiên Thiên Ấn của Lam Mộng Đạo Tôn lần đầu trong thực chiến, tạo thiên địa hư ảnh nghịch chuyển đè bẹp Bạch Y Nữ Tử, phá sụp phòng hộ ban đầu của nàng. Hắn lạnh lùng phân tích đối phương chỉ là hình chiếu phân thân tu vi thiên nhân tam suy, không phải thực thể hay tu sĩ Đệ Tam Bộ, đồng thời tố cáo nàng dùng ảo thuật ảnh hưởng tâm thần. Hắn tung chiến hồn trong Hô Phong Hoán Vũ giới tấn công ồ ạt, nữ tử thi triển Thiên Linh Quang phá giới nhưng không thương tổn chiến hồn, ngưng hắc quang thành trường kiếm đen tấn công nhưng bị Quang Ảnh Thuẫn phản chiết xạ ngược. Vương Lâm rút huyết kiếm chém nứt ngọc bội nữ tử khiến nàng phun máu bỏ chạy, phân thân có máu tươi khiến hắn sửng sốt. Nữ tử tuyệt vọng kêu cứu bổn tôn, từ ngọc bội hiện ra cánh tay trắng như ngọc ấn ngón tay xuống với uy lực vượt cả Thủy Đạo Tử, khiến Vương Lâm cảm nhận nguy cơ sinh tử mãnh liệt. Ngón tay xuyên phá Quang Ảnh Thuẫn hoàn toàn, đụng vào Hô Phong Hoán Vũ giới khiến chiến hồn kêu thê lương, khí tức trắng sữa lan ra đối kháng. Trận chiến kết thúc ở thế cliffhanger, tình huống cực kỳ nguy hiểm cho Vương Lâm."},{"chuong":1250,"tieuDe":"Truy Sát","tomTat":"Ngón tay triệu hồi bổn tôn của Bạch Y Nữ Tử phá vỡ Quang Ảnh Thuẫn và ấn lõm Hô Phong Hoán Vũ giới, Vương Lâm rút đốt xương Cổ Thần chắn đỡ, bị một tia lực xuyên ngực nhưng nhờ thân Cổ Thần hồi phục tức khắc. Vương Lâm phản kích bằng huyết kiếm chém đứt cánh tay triệu hồi, ngọc bội Bạch Y Nữ Tử vỡ tan, cắt đứt kết nối bổn tôn. Thế cục đảo ngược hoàn toàn, Vương Lâm dung nhập thiên địa truy sát nữ tử liên tục trong Thái Cổ Tinh Thần, thi triển lôi đình cắt đường rồi Phiên Thiên Ấn đánh trúng, huyết kiếm đâm xuyên hậu tâm. Lúc bị thương nặng, không gian quanh thân nữ tử hiện hình ảnh cảnh quỳ trước cánh tay trắng nõn, từ thiên linh phóng ra lực hương hỏa môn đồ nồng đậm vượt ba thành Hô Phong Hoán Vũ giới với tia sáng vàng bên trong. Nữ tử chạy tới tinh vực Ma Hạt Tộc tự xưng là một trong những phân thân của Lan Phi, sai mấy ngàn tu sĩ dùng mạng ngăn cản, nhưng Vương Lâm hóa thân Cổ Thần ngàn trượng dùng Quang Ảnh phản xạ mọi thần thông khiến tu sĩ chết thương vô số, một quyền tạo khe nứt tinh không bức nữ tử hiện hình."},{"chuong":1251,"tieuDe":"Âm Mưu","tomTat":"Trong lúc Vương Lâm truy sát, ấn ký mi tâm Bạch Y Nữ Tử kích hoạt, hé lộ ký ức nàng từng là thánh nữ bộ tộc bị biến thành phân thân nuôi dưỡng hình chiếu và cánh cửa hương hỏa cho một thực thể bí ẩn. Khí tức trắng sữa bùng lên giúp nàng thoát đi bằng na di tới phía đông Thái Cổ Tinh Thần, thân thể dần trong suốt sắp biến mất. Vương Lâm truy kích kịp, thi triển Định Thần Thuật đóng băng trời đất, dùng bổn nguyên lực kéo nàng ra khỏi hư vô rồi dùng huyết kiếm đâm thiên linh phá nguyên thần, đoạt hồn phách cùng hương hỏa. Khi Bạch Y Nữ Tử chết, một đạo kim tuyến phân thân của Lan Phi từ trong thi thể lao vào hư vô, huyết kiếm chém không trúng vì kim tuyến phi vật chất. Ngân Y Nữ Thi bất ngờ tự thoát khỏi khe trữ vật, tùy ý kéo kim tuyến đã biến mất trong hư vô quay lại rồi nuốt vào thất khiếu, thể hiện sức mạnh vượt xa Vương Lâm. Trước khi quay vào khe trữ vật, Ngân Y Nữ Thi cảnh báo rằng hương hỏa là một âm mưu rất lớn, nàng dường như vì nó mà mất đi hết thảy, hoàn toàn trái ngược với những gì các cường giả từng nói về hương hỏa là mấu chốt bước thứ ba. Vương Lâm chấn động trầm tư, tự nhủ cả đời tu đạo chưa bao giờ dựa vào môn đồ hương hỏa, quyết tâm cảnh giác, rồi nhắm tới Thiểm Lôi Tộc nơi không có tu sĩ Đệ Tam Bộ nhưng sở hữu đạo thiểm điện vạn năm bất diệt, định nuốt thánh vật này để lôi bổn nguyên tiến thêm bước lớn."},{"chuong":1252,"tieuDe":"Đoạt Xá","tomTat":"Vương Lâm đứng ngoài tinh vực Thiểm Lôi Tộc — một lôi trì khổng lồ tràn ngập sấm sét trong Thái Cổ Tinh Thần. Nhờ đã hấp thụ sấm sét pho tượng ở thế giới bảy màu, nuốt Đạo quả và ngộ lôi bản nguyên, hắn chậm rãi xâm nhập lôi trì mà sấm sét không thể gây hại. Tiến vào sâu nhất, hắn khoanh chân thổ nạp, khí tức hoàn toàn tiêu tán, dung hợp hoàn toàn với lôi trì trở thành một phần của nó. Ký hiệu tia chớp từ mắt phải phóng ra xuyên lôi trì, tất cả sấm sét nhường đường chỉ phương hướng. Thiểm Lôi Tộc được giới thiệu là bộ tộc hùng mạnh với mười sáu tu chân tinh xếp vòng tròn, trung tâm là đại lục Vân Tàn — thánh địa có miếu thờ bị tia chớp đen đánh liên tục vài ngàn năm. Trên tu chân tinh màu vàng, một thanh niên hắc y tộc nhân Thiểm Lôi Tộc bị thương nặng, tuyệt vọng oán hận thân phận, trước khi chết tự kéo ký hiệu tộc trên mi tâm ra ngoài. Tia chớp của Vương Lâm phát hiện thanh niên này và phóng thẳng vào vết thương mi tâm, thực hiện đoạt xá thân xác."},{"chuong":1253,"tieuDe":"Thiểm Lôi Bảng","tomTat":"Một phần nguyên thần Vương Lâm đoạt xá thành công thân thể Vu Phi — thanh niên hắc y Thiểm Lôi Tộc đang hấp hối, trong khi bản thể vẫn ở lôi vực dung nhập lôi trì. Qua ký ức Vu Phi, hắn biết đây là tộc nhân tầm thường bị tu sĩ Nguyên Anh sơ kỳ Tề Trì cướp mất động phủ truyền thừa và hút tu vi. Vương Lâm nhận ra hệ thống tu luyện Thái Cổ Tinh Thần dựa trên ký hiệu mi tâm bắt nguồn từ sấm sét bất diệt, còn ký hiệu do hắn tự sinh ra có cấp độ cao hơn rất nhiều. Trên đường đến động phủ, hắn chỉ bằng ánh mắt phá vỡ Kim Đan ba tu sĩ Kết Đan dám khinh nhờn. Xâm nhập động phủ Tề Trì, hắn dễ dàng đánh bại lão Nguyên Anh, dùng Sưu Thần Thuật lục ký ức, lấy hết bảo vật nhưng không giết vì luật tộc cấm chém giết sinh tử. Từ ký ức Tề Trì, Vương Lâm nắm được hệ thống Lôi Tinh và Thiểm Lôi Bảng: mỗi trăm năm tám trăm người trên mười ba tu chân tinh tranh đoạt một suất duy nhất vào thánh địa tiếp xúc sấm sét bất diệt, cuộc tranh đoạt tiếp theo chỉ còn bảy năm. Hắn quyết định dùng danh tính Vu Phi tích lũy Lôi Tinh để quang minh chính đại giành suất vào thánh địa, nhưng ngay lúc đó đội của Tộc Quyền thuộc Thiên Lôi Tông gồm một Nguyên Anh trung kỳ cùng ba Kết Đan đang phóng đến cướp bảo vật động phủ này."},{"chuong":1254,"tieuDe":"Vì Tiền Bối","tomTat":"Vương Lâm trong động phủ Tề Trì bóp vỡ Lôi quả hấp thu sấm sét vào nguyên thần, nhận ra một quả đổi được một khối Lôi Tinh. Khâu Đức Hải — một trong tứ đại trưởng lão Nguyên Anh Thiên Lôi Tông — dẫn ba tu sĩ Kết Đan đến đòi cống nạp pháp bảo đan dược cho tông chủ tiến vào Thiểm Lôi Bảng. Vương Lâm bước ra bùng uy áp, phá ký hiệu mi tâm ba Kết Đan khiến Kim Đan vỡ, cướp pháp bảo. Khâu Đức Hải đẩy đồng đội làm vật cản bỏ chạy, thuấn di hơn mười lần gần mười vạn dặm, bóp nát ngọc giản cầu cứu. Lần lượt ba đồng môn Nguyên Anh Thiên Lôi Tông nhập bọn chạy trốn. Vương Lâm ép cả bốn trưởng lão dẫn đường về sơn môn, tại đó vung tay phá ký hiệu mi tâm cả bốn, cướp sạch bảo vật ném bốn người xuống quảng trường. Từ đại điện phóng ra một tu sĩ Hóa Thần sơ kỳ gầy gò xấu xí, cuồng nhiệt sùng bái Vương Lâm, tự nguyện dâng pháp bảo xin làm tôi tớ, khiến Vương Lâm sửng sốt nhớ tới Hứa Lập Quốc."},{"chuong":1255,"tieuDe":"Kình Địch","tomTat":"Chung Đại Hồng, tông chủ Thiên Lôi Tông, dùng kỹ thuật nịnh hót bảo toàn tu vi trước Vương Lâm, giao nộp toàn bộ vật phẩm đổi Lôi tinh gồm cành cây Lôi quang, đan dược tử quang và phi kiếm sắc bén. Vương Lâm gọi Hứa Lập Quốc ra khỏi túi trữ vật, truyền thần niệm giao nhiệm vụ cướp vật đổi Lôi tinh trên lãnh thổ Thiểm Lôi Tộc. Vương Lâm tặng Hàm Hồn đan cho Chung Đại Hồng để buộc hắn sưu tập vật phẩm, tính kế không dùng đan dược mình đổi trực tiếp vì sẽ tăng thực lực cho Thiểm Lôi Tộc. Hứa Lập Quốc và Chung Đại Hồng nhận ra nhau cùng tu luyện pháp thuật nịnh hót, coi nhau là kình địch. Hứa Lập Quốc ghen tức, nảy ý dùng Lưu Kim Bưu đi giết Chung Đại Hồng, lộ nụ cười âm hiểm."},{"chuong":1256,"tieuDe":"Thế Này Mới Là Sống Chứ!","tomTat":"Vương Lâm ở lại Thiên Lôi Tông một tháng thổ nạp, sai Hứa Lập Quốc và Chung Đại Hồng lấy Thiên Lôi Tông làm trung tâm quét bốn phía thu gom vật phẩm, đã gom được gần mười vạn Lôi tinh. Hứa Lập Quốc được thả ra ngoài, hưng phấn thu phục gần trăm tu sĩ Thiểm Lôi Tộc, bắt họ chế ngai vàng trăm trượng khiêng đi, bốn nữ tu và bốn thanh niên hầu hạ, sai người gào khẩu hiệu, tận hưởng cuộc sống đế vương sau hai ngàn năm bị Vương Lâm sai khiến. Hứa Lập Quốc thi triển kiếm khí phá tan trận pháp sương đen của lão quái Nguyên Anh hậu kỳ, thu phục đối phương, nghe tin tông phái Lôi Tiên Đạo có tông chủ xinh đẹp tuyệt trần liền dẫn đoàn tiến quân cướp người đoạt bảo. Chung Đại Hồng được Vương Lâm ban phi kiếm và đan dược, chiến lực tăng mạnh, cẩn thận vơ vét vật phẩm ở hướng khác, coi Hứa Lập Quốc là kình địch cả đời. Cuối chương Vương Lâm nghiên cứu ngọc giản chứa công pháp Tụ Lôi Ấn của Thiểm Lôi Tộc, mục đích thật sự là điều tra tộc ấn vì mơ hồ cảm giác việc hấp thu sấm sét bất diệt cực kỳ quan trọng."},{"chuong":1257,"tieuDe":"Một Suy Đoán Đáng Sợ","tomTat":"Vương Lâm lĩnh ngộ công pháp Tụ Lôi Ấn từ ngọc giản Thiểm Lôi Tộc, thử thi triển nén sấm sét ba vạn lần đạt cực hạn thân thể Vu Phi, nhận xét nguyên thần hắn đã thành sấm sét vượt cả lão tổ Thiên Nhân Ngũ Suy. Sau hơn một tháng nghiên cứu tộc ấn trên mi tâm thân thể Vu Phi, hắn phát hiện bên trong ký hiệu ẩn giấu một ý chí ngủ say có thể hấp thu sấm sét từ tộc nhân — cơ chế cực kỳ giống Môn Đồ Hương Hỏa, tộc nhân thực chất dâng tính mạng và sấm sét cho sấm sét bất diệt. Mở rộng suy đoán, hắn cho rằng toàn bộ Thái Cổ Tinh Thần có thể là vùng nuôi dưỡng của một tồn tại tu vi siêu việt, liên hệ đến thế giới Thủy Đạo Tử chứa hai mươi tỷ môn đồ, đại trận Phong giới, lời Ngân Y Nữ Tử về hương khói có độc và Lam Mộng Đạo Tôn bị tiếng rống người Nội giới trọng thương. Hắn kiên quyết tuyệt đối không tu luyện hương hỏa. Vài ngày sau Chung Đại Hồng trở về trước Hứa Lập Quốc, dâng đống vật phẩm đổi Lôi tinh, được Vương Lâm ban một viên thuốc, đề nghị đi đến Lôi Tinh Điện sắp mở cửa để đổi Lôi tinh."},{"chuong":1258,"tieuDe":"Lôi Tinh Điện","tomTat":"Vương Lâm cùng Chung Đại Hồng phi hành hơn nửa thống đến vùng trung tâm tu chân tinh để đến Lôi Tinh Điện — nơi tộc nhân Thiểm Lôi Tộc đổi vật phẩm lấy Lôi tinh, mỗi năm chỉ mở ba ngày. Trên đường đi, Chung Đại Hồng nịnh hót chu đáo, đổi cách xưng hô thành 'chủ tử' theo kiểu Hứa Lập Quốc, chủ động vơ vét vật phẩm đổi Lôi tinh của kẻ gặp trên đường rồi nộp hết cho Vương Lâm. Hắc Ma Pháp Vương — tu sĩ Vấn Đỉnh sơ kỳ đỉnh phong, hạng 766 Thiểm Lôi Bảng — phóng ngang qua nhưng chỉ bị Vương Lâm quét mắt liền run rẩy toàn thân, vã mồ hôi lạnh, vội phóng đi. Tại khe nứt sương mù dẫn vào Lôi Tinh Điện, hai tu sĩ áo đỏ tu vi Âm Hư canh gác. Tu sĩ Khuy Niết Chu Thiên Tử xuất hiện từ mây sấm sét, tuyên bố nhắm nhóm ba mươi Thiểm Lôi Bảng, thưởng đan dược cho lính canh rồi tiến vào. Vương Lâm và Chung Đại Hồng bước vào khe nứt mà không bị phát hiện bất thường. Khi tiến vào, Vương Lâm nhìn chằm chằm sương mù xanh bốn phía, trong mắt bùng ra ánh sáng kỳ dị, dường như phát hiện điều gì đó đặc biệt về sương mù."},{"chuong":1259,"tieuDe":"Chính Thức Tiến Lên Thiểm Lôi Bảng","tomTat":"Vương Lâm cùng Chung Đại Hồng đi qua khe nứt sương mù sấm sét dẫn đến Lôi Tinh Điện. Trong khe nứt, Vương Lâm nhận ra sương mù thực chất là sấm sét hóa thành bằng thuật đại thần thông, lợi dụng cấu trúc bộc lộ để dùng thần thức sấm sét xâm nhập thôi diễn ngược lại, học được tuyệt học thất truyền Hóa Lôi Vi Vụ của Thiểm Lôi Tộc — là người đầu tiên trong lịch sử làm được. Ra khỏi khe nứt, Chung Đại Hồng giới thiệu ba cửa của Lôi Tinh Điện; Vương Lâm dùng thần thức quét thấy tầng không gian thứ tư có chín cường giả đang thổ nạp. Vào cửa đông, Vương Lâm che giấu tu vi thành Vấn Đỉnh trước mặt ba lão già canh ao, ném lượng lớn vật phẩm vào ao đen suốt nửa ngày đổi Lôi tinh bằng ngọc giản mệnh hồn của Vu Phi. Tên Vu Phi chính thức xuất hiện trên Thiểm Lôi Bảng ở vị trí 799 với bốn mươi sáu vạn bốn ngàn Lôi tinh, gây xôn xao tộc nhân trên mười ba tu chân tinh."},{"chuong":1260,"tieuDe":"Bí Mật Thiểm Lôi Tộc","tomTat":"Vương Lâm định rời Lôi Tinh Điện thì được ba lão già Dương Thực cửa đông tặng tạo hóa theo quy củ dành cho người mới lên Thiểm Lôi Bảng: Tụ Lôi Hoàn nén 8900 lần, ngọc giản công pháp Thiểm Lôi Tộc mở rộng tộc ấn, và ngọc giản lôi quang để nhận nhiệm vụ cửa tây. Lão già thứ ba tiết lộ bí mật Lôi Lục Đạo — sấm sét chia làm sáu loại, bảo Vương Lâm đi nhận nhiệm vụ Linh Niệm Lôi. Vương Lâm chuyển sang cửa tây, kiểm tra ngọc giản sáng nhất và phát hiện bí mật kinh hoàng: tổ tiên Thiểm Lôi Tộc cùng Đệ Tam Bộ đại năng tạo ra bảy trăm vạn thế giới chứa sinh linh tu luyện, tộc nhân đóng vai thiên đạo giáng thiên kiếp hủy diệt tu sĩ Hóa Thần đỉnh phong, tu sĩ thiên tài ngưng tụ Linh Niệm Lôi khi độ kiếp thực chất bị hình thần câu diệt. Vương Lâm nhận ra người tự xưng Thiên Đạo gặp khi chiến đấu với Vọng Nguyệt chính là tộc nhân Thiểm Lôi Tộc, nhưng vẫn quyết tâm hấp thu sấm sét bất diệt. Khi Vương Lâm định chộp ngọc giản nhiệm vụ Linh Niệm Lôi, Chu Thiên Tử ở gần hơn chộp trước và quát Cút với uy áp Khuy Niết, Vương Lâm lóe sát ý trong mắt."},{"chuong":1261,"tieuDe":"Giết Chu Thiên Tử","tomTat":"Vương Lâm dùng thân phận Vu Phi đưa ngọc giản cho lão tu sĩ cửa Tây Lôi Tinh Điện, được lão xin Chu Thiên Tử nể mặt cho vào bảy trăm vạn thiên địa tu luyện. Chu Thiên Tử khinh thường Vương Lâm vì tưởng chỉ là tu sĩ Vấn Đỉnh, quyết định để hắn vào bảy trăm vạn thiên địa rồi giết ở trong đó vì nơi đó có cấm chế chặn thần thức. Chu Thiên Tử tiến vào trước, suy tính giao dịch với Hạo Côn Tử. Vương Lâm theo sau, phá nát tất cả không gian loạn lưu trên đường, ung dung đuổi kịp Chu Thiên Tử. Chu Thiên Tử toàn lực hóa Lôi Long tấn công nhưng bị Vương Lâm phá tan chỉ bằng một vung tay, lộ tu vi vượt xa Toái Niết. Chu Thiên Tử hồn bay phách lạn bỏ chạy. Bản nguyên chiến ý của Chiến Tinh Dã được khẳng định đã ăn sâu vào gốc rễ tâm thần Vương Lâm."},{"chuong":1262,"tieuDe":"Không Có Ý Tốt","tomTat":"Chu Thiên Tử bỏ chạy về phía cửa ra vào bảy trăm vạn thiên địa nhưng bị Vương Lâm chặn lại, dùng thần thông qua ánh mắt kích nổ toàn bộ sấm sét trong cơ thể lão, phá tan thân xác. Nguyên thần trọng thương của Chu Thiên Tử được tộc ấn bảo vệ xông ra nhưng bị hút ngược, cầu xin tha mạng, kịp nhìn thấy hồn phách bị phong ấn trong cơ thể trong suốt của Vương Lâm và kêu lên trước khi bị bóp nát nguyên thần, hình thần câu diệt. Vương Lâm hấp thu sấm sét và lấy tộc ấn, sau đó phá cửa tiến vào bảy trăm vạn thiên địa — trọng địa Thiểm Lôi Tộc — trở thành người ngoài đầu tiên xâm nhập kể từ đám tu sĩ thần bí năm xưa. Mạo danh Vu Phi, Vương Lâm dùng ngọc giản tộc qua kiểm tra của tu sĩ Âm Hư, nhận linh phù, ngọc giản hướng dẫn và Linh Niệm Lôi. Vương Lâm nghiên cứu Linh Niệm Lôi, nhận ra nó giống sinh linh chứa ý niệm sinh cơ, cần thu thập đủ một ngàn luồng mới thành niệm lôi hoàn chỉnh, mỗi người cả đời chỉ có một cơ hội. Tu sĩ Vấn Đỉnh trung kỳ Trương Cảnh Vân — kẻ chuyên cướp Linh Niệm Lôi và hại mạng người mới — chủ động tiếp cận dụ dỗ Vương Lâm, nhưng Vương Lâm nhìn thấu ý đồ và giả vờ đồng ý, bị dẫn đến tổ hơn mười người trước trận pháp khổng lồ."},{"chuong":1263,"tieuDe":"Đây Là Thiên Kiếp Sao?","tomTat":"Trương Cảnh Vân dẫn Vương Lâm (danh giả Vu Phi) đến giới thiệu với nhóm bốn tu sĩ, thực chất là bọn lừa đảo chuyên thu niệm lôi của người mới. Bốn tên truyền âm bàn mưu, dựa vào Triệu tiền bối tu vi Âm Hư, định gộp niệm lôi thành Linh Niệm Lôi đổi phi kiếm tiên phẩm tại Lôi Tinh Điện. Vương Lâm nhìn rõ tâm tư giả tạo của chúng nhưng không thèm quan tâm. Cả nhóm tiến vào trận pháp, truyền tống đến thiên địa nơi lão tu sĩ Vi Lỗ Bị đang nghênh đón thiên kiếp. Kiếp vân ngưng tụ bao phủ bầu trời, trên đó xuất hiện mười hư ảnh Tiên nhân — Vương Lâm là một trong số đó. Trương Cảnh Vân xin đóng vai thiên đạo, hưng phấn điều khiển sáu luồng sấm sét đánh xuống Vi Lỗ Bị. Vi Lỗ Bị phun máu, rống lên tiếng cuối rồi hình thần câu diệt. Khi nghe tu sĩ họ Chu giải thích sấm sét mạnh dần là để buộc tu sĩ sinh ra Linh Niệm Lôi, Vương Lâm tâm thần rung động mãnh liệt, nhận ra thiên kiếp hắn từng trải qua cũng đều do tu sĩ Lôi Tiên Giới hóa thân thiên đạo mà giáng xuống."},{"chuong":1264,"tieuDe":"Ta Chính Là Thiên Kiếp","tomTat":"Trương Cảnh Vân bước vào kiếp vân, tiếc nuối rằng lão già Hóa Thần đỉnh phong vừa chết không sinh ra Linh Niệm Lôi, lộ ra mục đích thật sự của thiên kiếp giả là kích thích tu sĩ sinh Linh Niệm Lôi. Hắn khinh thường tấn công Vương Lâm bằng sấm sét giả thiên kiếp nhưng bị Vương Lâm vung tay siết chết, hình thần câu diệt. Vương Lâm tuyên bố mình chính là thiên đạo của bọn họ, dùng Cực Cảnh phóng tia chớp hồng sắc từ mắt lần lượt giết sạch ba tu sĩ Vấn Đỉnh và tu sĩ Âm Hư, không ai trốn thoát hay tự bạo được. Hắn xác nhận cực cảnh chính là thiên kiếp, dù thân đoạt xá có rất ít vẫn thi triển được. Thi thể tu sĩ Âm Hư rơi xuống trước mặt mấy ngàn tu sĩ phàm, tiên khí tiêu tán, Vương Lâm nói đây chính là Tiên nhân trong mắt các ngươi rồi biến mất. Tán Linh Thượng Nhân — thanh niên đầu trọc tu vi mơ hồ đạt Tịnh Niết — xuất hiện lấy thi thể, nhận xét Vương Lâm có lẽ không phải nô lệ của sấm sét. Ngoài bảy trăm vạn thiên địa, Hứa Lập Quốc tiếp tục điên cuồng vơ vét trên tu chân tinh, ngai vàng mở rộng lên năm trăm trượng, bị một nữ tu tướng mạo tuyệt vời mắng hắn chỉ là khí linh và đe dọa diệt sạch cả chủ nhân."},{"chuong":1265,"tieuDe":"Con Đường Lôi Tu Đại Năng","tomTat":"Vương Lâm bóp nát hơn mười tộc ấn Thiểm Lôi Tộc, dung hợp gần ngàn luồng Linh Niệm Lôi thành một luồng hoàn chỉnh hình quả cầu khói. Linh Niệm Lôi tự phóng xuyên mắt phải nhập nguyên thần, kích hoạt ký ức lôi bản nguyên từ thuở thiên địa sơ khai, tiết lộ lôi thực tế có Cửu đạo chứ không phải Lục đạo. Vương Lâm minh ngộ con đường tu luyện: hấp thu đủ chín loại sấm sét cộng lôi bản nguyên thành mười viên mãn thì đại thành, có thể đột phá Đệ Nhị Bộ lên Đệ Tam Bộ đại năng. Mắt phải xuất hiện tia chớp thứ hai nhỏ hơn vờn quanh ký hiệu gốc, lôi bản nguyên dần tăng trưởng. Quyết định không giết tu sĩ độ kiếp mà giết tộc nhân Thiểm Lôi Tộc đoạt niệm lôi, hóa gió bão sấm sét vạn trượng tàn sát hơn ngàn tu sĩ Thiểm Lôi Tộc trong vài ngày, thu bốn luồng lôi niệm hoàn chỉnh. Ngày thứ tư linh phù cảm ứng có người muốn độ kiếp gần đó nhưng đã có tu sĩ khác đến trước, Vương Lâm cầm linh phù thuấn di về phía đó."},{"chuong":1266,"tieuDe":"Mồi Nhử","tomTat":"Vương Lâm dùng kế mồi nhử: lợi dụng một người đàn ông trung niên tu vi Hóa Thần đỉnh phong đang chờ thiên kiếp để dụ Tiên nhân Thiểm Lôi Tộc đến qua lỗ hổng trên kiếp vân. Tiên nhân Khuy Niết hậu kỳ đại viên mãn đầu tiên xuất hiện bị Vương Lâm giết bằng một ngón tay điểm ót, hình thần câu diệt, tộc ấn bị thu. Vương Lâm bóp nát hạt châu lôi quang của lão, mắt phải hấp thu năm luồng niệm lôi. Trong nửa canh giờ tiếp theo, hơn một trăm tộc nhân Thiểm Lôi Tộc lục tục phóng xuống đều bị giết. Một tu sĩ Toái Niết dùng thuật phân thân bỏ chạy cũng bị Vương Lâm dùng tia chớp đỏ cực cảnh hủy diệt nguyên thần. Hiện tại Vương Lâm không phải bản thể nên không có cực cảnh trong người, chỉ dựa tu vi Toái Niết nhưng có thể triệu hồi cực cảnh hóa tia chớp đỏ. Cuối chương, Vương Lâm phát hiện Tán Linh Thượng Nhân ẩn trong hư không theo dõi, ép hắn lộ diện và yêu cầu giải thích lý do."},{"chuong":1267,"tieuDe":"Tán Linh Thượng Nhân","tomTat":"Vương Lâm phát hiện thanh niên đầu láng bám đuôi mình, liền phóng tia chớp hồng sắc xuyên mi tâm đối phương để kích hoạt bản thể thật ẩn bên trong. Linh hồn cực mạnh hiện ra, xưng là Tán Linh thượng nhân, tồn tại hơn vài vạn năm, tu vi đạt Toái Niết, sở hữu 971 phân thân người thường chứa tu vi để tránh thiên kiếp. Tán Linh kể lại lai lịch: năm xưa hắn nghi ngờ bản chất Tiên nhân, bị đại trưởng lão Thiểm Lôi Tộc phế tu vi nhưng giữ mạng nhằm tăng cơ hội sinh Linh Niệm Lôi. Hắn tự sáng tạo thuật Tán Linh, chia tu vi vào phân thân rồi lặp chu trình hợp-tán, từ Hóa Thần tu lên Toái Niết qua hàng vạn năm. Qua quá trình quan sát thiên kiếp và tận mắt thấy thi thể Tiên nhân thối rữa, Tán Linh phát hiện chân tướng kinh thiên: bảy trăm vạn thiên địa chỉ là lao ngục do kẻ khác tạo ra để sưu tập Linh Niệm Lôi, mọi sinh mạng bên trong chẳng qua là kiến hôi. Tán Linh đề nghị giao dịch với Vương Lâm, mời hắn cùng đến tận cùng thế giới, quyết tâm phá vỡ lao ngục bước vào tinh không."},{"chuong":1268,"tieuDe":"Tận Cùng Thiên Địa","tomTat":"Tán Linh Thượng Nhân kể cho Vương Lâm toàn bộ chân tướng bảy trăm vạn thiên địa: nơi đây là ngục tù do Thiểm Lôi Tộc tạo ra, tu sĩ bị nuôi như súc vật, thiên đạo và thiên kiếp chỉ là nhiệm vụ thu hoạch Linh Niệm Lôi khi tu sĩ đạt Hóa Thần, mọi giai thoại tiên giới đều giả. Hắn kể hành trình phát hiện chân tướng: phá phòng hộ tu chân tinh thấy tinh không, giết tu sĩ Thiểm Lôi Tộc rồi biết sự thật, sợ hãi trốn chạy đến tận cùng thế giới nơi có bức tường ngăn cách khổng lồ, rồi quyết tâm phản kháng. Hắn quay về lập Tán Linh Tông dùng phân thân truyền bá, tu luyện vài ngàn năm đạt Thiên Nhân Tứ Suy nhưng vẫn không thắng đại trưởng lão Thiên Nhân Ngũ Suy. Tán Linh cầu xin Vương Lâm liên thủ với nhiều điều kiện, Vương Lâm đồng ý vì muốn giúp người này phá vỡ ngục tù. Tán Linh tự hủy mấy vạn phân thân ngưng tụ thành linh phù huyết sắc trao cho Vương Lâm để sau này mở đường vào bảy trăm vạn thiên địa. Vương Lâm nhận linh phù rồi phóng về quảng trường trung tâm, cưỡng bức xé rách trận pháp truyền tống đang vận chuyển để tiến vào, gây kinh hoàng cho tu sĩ Thiểm Lôi Tộc."},{"chuong":1269,"tieuDe":"Chủ Nhân Ở Đâu!","tomTat":"Hứa Lập Quốc (kiếm linh) bắt cóc con nuôi xinh đẹp của một cường giả Toái Niết viên mãn Thiểm Lôi Tộc làm con tin, hóa thành sương đen bỏ chạy trong lãnh địa Thiểm Lôi Tộc. Lão già áo xanh — trưởng lão Tịnh Niết Thiểm Lôi Tộc — truy kích kịch liệt bằng lôi cầu màu đen từ tộc ấn, Hứa Lập Quốc dùng cô gái làm lá chắn và liên tục chửi bới khiêu khích để câu giờ. Cha nuôi cô gái (Toái Niết viên mãn) xuất hiện, đánh tan thân thể Hứa Lập Quốc thành nhiều mảnh rồi liên tục tra tấn bằng cách làm tan rã rồi khôi phục, Hứa Lập Quốc gần như diệt vong. Trong lúc tuyệt vọng, Hứa Lập Quốc kêu gọi chủ nhân. Vương Lâm xuất hiện giữa sấm sét trên bầu trời, tuyên bố là chủ nhân của Hứa Lập Quốc. Khi lão già áo xanh vô tình ngăn cản Hứa Lập Quốc, Vương Lâm điểm lên mi tâm lão khiến thân thể tan vỡ và nguyên thần diệt vong chỉ bằng một chỉ, thể hiện sức mạnh áp đảo. Cường giả Toái Niết viên mãn khiếp sợ, giữ chặt cô gái muốn bỏ trốn."}];
